// ── Assets ────────────────────────────────────────────────────────────────────
const LOGO_SRC  = "data:image/png;base64,";
const STAMP_SRC = "data:image/png;base64,";

// ── Config ────────────────────────────────────────────────────────────────────
const API      = import.meta.env.VITE_API_URL || "/api";
const PASSWORD = "nks2026";

// ── Theme ─────────────────────────────────────────────────────────────────────
const G1 = "#c9972b", G2 = "#a67c1a", DARK = "#0a0700";
const fmt = n => "₹" + Number(n).toFixed(2);

// ── Helpers ───────────────────────────────────────────────────────────────────
function todayYMD() {
  const d = new Date(), p = n => String(n).padStart(2,"0");
  return `${d.getFullYear()}${p(d.getMonth()+1)}${p(d.getDate())}`;
}
const fmtDate = iso => new Date(iso).toLocaleDateString("en-IN",{day:"2-digit",month:"short",year:"numeric"});
const fmtTime = iso => new Date(iso).toLocaleTimeString("en-IN",{hour:"2-digit",minute:"2-digit"});

// ── API fetch ─────────────────────────────────────────────────────────────────
async function apiFetch(path, opts = {}) {
  try {
    const res = await fetch(API + path, {
      headers: { "Content-Type": "application/json" },
      ...opts,
      body: opts.body ? JSON.stringify(opts.body) : undefined,
    });
    return await res.json();
  } catch(e) { return { success: false, message: e.message }; }
}

// ── Script loaders ────────────────────────────────────────────────────────────
const loadH2C = () => new Promise((res,rej) => {
  if(window.html2canvas){res();return;}
  const s=document.createElement("script");
  s.src="https://cdnjs.cloudflare.com/ajax/libs/html2canvas/1.4.1/html2canvas.min.js";
  s.onload=res;s.onerror=rej;document.head.appendChild(s);
});
const loadPDF = () => new Promise((res,rej) => {
  if(window.jspdf){res();return;}
  const s=document.createElement("script");
  s.src="https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js";
  s.onload=res;s.onerror=rej;document.head.appendChild(s);
});

async function captureJPG(cardId, billId, hideId) {
  await loadH2C();
  const el=document.getElementById(cardId);
  const hide=hideId?document.getElementById(hideId):null;
  if(hide)hide.style.opacity="0";
  const cv=await window.html2canvas(el,{scale:2,useCORS:true,backgroundColor:"#fff"});
  if(hide)hide.style.opacity="1";
  const a=document.createElement("a");
  a.download=`NKS-${billId}.jpg`;a.href=cv.toDataURL("image/jpeg",0.95);a.click();
}
async function capturePDF(cardId, billId, hideId) {
  await loadH2C();await loadPDF();
  const el=document.getElementById(cardId);
  const hide=hideId?document.getElementById(hideId):null;
  if(hide)hide.style.opacity="0";
  const cv=await window.html2canvas(el,{scale:2,useCORS:true,backgroundColor:"#fff"});
  if(hide)hide.style.opacity="1";
  const img=cv.toDataURL("image/jpeg",0.95);
  const {jsPDF}=window.jspdf;
  const pdf=new jsPDF({orientation:"portrait",unit:"mm",format:"a5"});
  const pw=pdf.internal.pageSize.getWidth(),ph=pdf.internal.pageSize.getHeight();
  const ratio=cv.width/cv.height;
  let w=pw-16,h=w/ratio;if(h>ph-16){h=ph-16;w=h*ratio;}
  pdf.addImage(img,"JPEG",(pw-w)/2,8,w,h);pdf.save(`NKS-${billId}.pdf`);
}
async function shareText(bill) {
  const text=`🏪 New Krishna Sweets\nBill: ${bill.billId}\nTotal: ₹${bill.total.toFixed(2)}\n\nPowered by Sai Shuru Nexus`;
  if(navigator.share){try{await navigator.share({title:"NKS Bill",text});}catch{}}
  else{try{await navigator.clipboard.writeText(text);}catch{}}
}

// ── Category emoji map ────────────────────────────────────────────────────────
const EMOJI_MAP = {sweet:"🍬",mixture:"🥨",bread:"🍰🍞",puffs:"🥐",icejuice:"🍨🍹",biscuit:"🍪🍫"};
const getCatEmoji = (id, cats=[]) => {
  const cat = cats.find(c=>(c._id||c.id)===id);
  if(cat) return cat.emoji;
  return EMOJI_MAP[id] || "🛍️";
};

