// ══════════════════════════════════════════════════════════════════════════════
// QR SVG — unique per billId
// ══════════════════════════════════════════════════════════════════════════════
function QRSvg({data,size=100}) {
  const N=25,cell=size/N;
  const seed=[...(data||"")].reduce((a,c,i)=>((a*31+c.charCodeAt(0)*(i+1))&0x7fffffff),0x5A3);
  const isFinder=(r,c)=>(r<7&&c<7)||(r<7&&c>=N-7)||(r>=N-7&&c<7);
  const isSep=(r,c)=>(r===7&&c<=7)||(r===7&&c>=N-8)||(c===7&&r<=7)||(c===7&&r>=N-8)||
    (r===N-8&&c<=7)||(r===N-8&&c>=N-8)||(c===N-8&&r<=7)||(c===N-8&&r>=N-8);
  const isTiming=(r,c)=>(r===6&&c>7&&c<N-8)||(c===6&&r>7&&r<N-8);
  const isAlign=(r,c)=>r>=N-10&&r<=N-6&&c>=N-10&&c<=N-6;
  const cells=Array.from({length:N*N},(_,i)=>{
    const r=Math.floor(i/N),c=i%N;
    if(isFinder(r,c)){if(r>0&&r<6&&c>0&&c<6)return r>1&&r<5&&c>1&&c<5;return true;}
    if(isSep(r,c))return false;if(isTiming(r,c))return(r===6?c:r)%2===0;
    if(isAlign(r,c))return!(r>=N-9&&r<=N-7&&c>=N-9&&c<=N-7)||r===N-8&&c===N-8;
    const v=((seed^(i*73856093))^((r*19+c*7)*2654435761))>>>0;return v%17<9;
  });
  return(
    <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}
      style={{display:"block",background:"#fff",borderRadius:4}}>
      <rect width={size} height={size} fill="#fff"/>
      {cells.map((on,i)=>on?<rect key={i} x={(i%N)*cell+.4} y={Math.floor(i/N)*cell+.4}
        width={cell-.8} height={cell-.8} rx={.4} fill="#1a0500"/>:null)}
    </svg>
  );
}

