// ══════════════════════════════════════════════════════════════════════════════
// PASSWORD GATE
// ══════════════════════════════════════════════════════════════════════════════
function PasswordGate({onUnlock}) {
  const [pw,setPw]=useState(""),[err,setErr]=useState("");
  const check=()=>{
    if(pw===PASSWORD){onUnlock();}
    else{setErr("Wrong password. Try again.");setPw("");}
  };
  return(
    <div style={{minHeight:"100vh",background:`linear-gradient(160deg,#090600,${DARK})`,
      display:"flex",alignItems:"center",justifyContent:"center",padding:20}}>
      <div style={{width:"100%",maxWidth:340,background:"linear-gradient(160deg,#150d00,#0d0800)",
        borderRadius:18,border:"1px solid rgba(201,151,43,.35)",padding:28,textAlign:"center",
        boxShadow:"0 20px 60px rgba(0,0,0,.8)"}}>
        <img src={LOGO_SRC} alt="NKS" style={{width:72,height:72,borderRadius:"50%",
          border:"3px solid #c9972b",objectFit:"cover",marginBottom:14}}/>
        <div style={{color:"#e8c060",fontSize:14,fontWeight:"bold",marginBottom:2}}>நியூ கிருஷ்ணா ஸ்வீட்ஸ்</div>
        <div style={{color:G1,fontSize:18,fontWeight:"bold",marginBottom:2}}>New Krishna Sweets</div>
        <div style={{color:"#8a6820",fontSize:10,letterSpacing:2,marginBottom:20}}>STAFF LOGIN</div>
        <div style={{fontSize:13,color:"#a07830",marginBottom:12}}>🔒 Enter Password</div>
        <input type="password" value={pw} onChange={e=>setPw(e.target.value)}
          onKeyDown={e=>e.key==="Enter"&&check()} placeholder="Password"
          style={{width:"100%",padding:"12px 14px",borderRadius:10,
            border:`2px solid ${err?"#ef4444":"rgba(201,151,43,.3)"}`,
            background:"rgba(201,151,43,.07)",color:"#f0ddb0",fontSize:14,
            outline:"none",textAlign:"center",letterSpacing:3,marginBottom:10,boxSizing:"border-box"}}/>
        {err&&<div style={{color:"#ef4444",fontSize:12,marginBottom:10}}>{err}</div>}
        <button onClick={check}
          style={{width:"100%",padding:"13px",borderRadius:10,border:"none",cursor:"pointer",
            background:`linear-gradient(135deg,${G2},${G1})`,color:"#000",fontSize:14,
            fontWeight:"bold",boxShadow:"0 4px 16px rgba(166,124,26,.4)"}}>
          🔓 Login
        </button>
        <PoweredBy/>
      </div>
    </div>
  );
}

// ══════════════════════════════════════════════════════════════════════════════
// CUSTOMER PORTAL — PUBLIC  (no nav, no password)
// Bill format: NKS-YYYYMMDD-XXXX  →  customer enters last 4 digits (XXXX)
// ══════════════════════════════════════════════════════════════════════════════
function CustomerPortal() {
  const [last4,setLast4]=useState("");
  const [bill,setBill]=useState(null);
  const [err,setErr]=useState("");
  const [loading,setLoading]=useState(false);
  const [busy,setBusy]=useState("");
  const [copied,setCopied]=useState(false);

  const todayPrefix = `NKS-${todayYMD()}-`;

  const search=async()=>{
    setErr("");setBill(null);
    const digits=last4.trim().replace(/\D/g,"");
    if(digits.length!==4){setErr("Please enter exactly 4 digits.");return;}
    setLoading(true);
    const res=await apiFetch(`/bills/lookup/${digits}`);
    setLoading(false);
    if(res.success)setBill(res.data);
    else setErr("Bill not found. Please check the 4-digit number and try again.");
  };

  const handle=async(type)=>{
    if(!bill)return;
    setBusy(type);
    const btns=document.getElementById("cp-btns");
    if(btns&&type!=="share")btns.style.opacity="0";
    try{
      if(type==="jpg")   await captureJPG("cp-card",bill.billId);
      else if(type==="pdf") await capturePDF("cp-card",bill.billId);
      else if(type==="print"){if(btns)btns.style.display="none";window.print();setTimeout(()=>{if(btns)btns.style.display="grid";},600);}
      else if(type==="share"){await shareText(bill);setCopied(true);setTimeout(()=>setCopied(false),2200);}
    }catch{}
    if(btns&&type!=="print")btns.style.opacity="1";
    setBusy("");
  };

  return(
    <div style={{minHeight:"100vh",background:"linear-gradient(160deg,#f7f2e8,#fff9ee,#f0e8d8)",
      display:"flex",flexDirection:"column",alignItems:"center",paddingBottom:30}}>
      {/* Hero */}
      <div style={{width:"100%",background:"linear-gradient(135deg,#1a0800,#3d1f00,#1a0800)",
        padding:"24px 16px 26px",textAlign:"center",boxShadow:"0 6px 24px rgba(0,0,0,.35)"}}>
        <img src={LOGO_SRC} alt="NKS" style={{width:70,height:70,borderRadius:"50%",
          border:"3px solid #c9972b",objectFit:"cover",display:"block",margin:"0 auto 10px",
          boxShadow:"0 4px 16px rgba(0,0,0,.5)"}}/>
        <div style={{color:"#e8c060",fontSize:14,fontWeight:"bold",marginBottom:2}}>நியூ கிருஷ்ணா ஸ்வீட்ஸ்</div>
        <div style={{color:G1,fontSize:20,fontWeight:"bold",marginBottom:3}}>New Krishna Sweets</div>
        <div style={{color:"#a07830",fontSize:9,letterSpacing:2,marginBottom:10}}>PREMIUM SWEETS • EST. 2010</div>
        <div style={{display:"inline-flex",alignItems:"center",gap:7,
          background:"rgba(201,151,43,.18)",border:"1px solid rgba(201,151,43,.4)",
          borderRadius:20,padding:"6px 16px"}}>
          <span style={{fontSize:14}}>📲</span>
          <span style={{color:G1,fontSize:11,fontWeight:"bold"}}>Customer Bill Portal</span>
        </div>
      </div>

      <div style={{width:"100%",maxWidth:400,padding:"16px 14px 0"}}>
        {/* Search card */}
        <div style={{background:"#fff",borderRadius:14,border:"1px solid #e8d5a0",
          boxShadow:"0 3px 14px rgba(0,0,0,.09)",padding:"16px 14px",marginBottom:14}}>
          <div style={{fontSize:14,fontWeight:"bold",color:"#5a2d00",marginBottom:4,
            display:"flex",alignItems:"center",gap:6}}>
            🔍 Find Your Bill
          </div>
          <div style={{fontSize:10,color:"#a07830",marginBottom:10}}>
            Enter the <b>last 4 digits</b> of your bill number
          </div>
          {/* Prefix + 4-digit input */}
          <div style={{display:"flex",alignItems:"center",gap:6,marginBottom:8,
            background:"#faf7f0",borderRadius:10,border:"1px solid #e8d5a0",
            padding:"10px 12px"}}>
            <span style={{fontSize:11,color:"#a07830",fontFamily:"monospace",fontWeight:"bold",whiteSpace:"nowrap"}}>
              {todayPrefix}
            </span>
            <input
              value={last4}
              onChange={e=>setLast4(e.target.value.replace(/\D/g,"").slice(0,4))}
              onKeyDown={e=>e.key==="Enter"&&search()}
              placeholder="3456"
              maxLength={4}
              inputMode="numeric"
              style={{width:70,padding:"6px 8px",borderRadius:7,border:"2px solid #e8d5a0",
                background:"#fff",color:"#2a1800",fontSize:18,outline:"none",
                fontFamily:"monospace",fontWeight:"bold",textAlign:"center",letterSpacing:4,
                transition:"border .2s"}}
              onFocus={e=>e.target.style.borderColor=G1}
              onBlur={e=>e.target.style.borderColor="#e8d5a0"}/>
          </div>
          <div style={{fontSize:9,color:"#a07830",marginBottom:10,textAlign:"center"}}>
            Example: Bill <b>NKS-{todayYMD()}-3456</b> → enter only <b style={{color:"#c9972b"}}>3456</b>
          </div>
          <button onClick={search} disabled={loading}
            style={{width:"100%",padding:"12px",borderRadius:9,border:"none",cursor:"pointer",
              background:`linear-gradient(135deg,${G2},${G1})`,
              color:"#000",fontSize:13,fontWeight:"bold",
              boxShadow:"0 3px 12px rgba(166,124,26,.35)",opacity:loading?.7:1}}>
            {loading?"🔍 Searching...":"Search Bill"}
          </button>
          {err&&(
            <div style={{marginTop:8,padding:"9px 12px",borderRadius:8,background:"#fef2f2",
              border:"1px solid #fecaca",color:"#dc2626",fontSize:12}}>❌ {err}</div>
          )}
          {bill&&!err&&(
            <div style={{marginTop:8,padding:"8px 12px",borderRadius:8,background:"#f0fdf4",
              border:"1px solid #bbf7d0",color:"#16a34a",fontSize:12}}>
              ✅ Bill found! Scroll down to download.
            </div>
          )}
        </div>

        {/* Bill + action buttons */}
        {bill&&(<>
          <BillCard bill={bill} cardId="cp-card" showSeal={true}/>
          <div id="cp-btns" style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginTop:11}}>
            <button onClick={()=>handle("jpg")} disabled={busy==="jpg"}
              style={{padding:"13px 8px",borderRadius:10,border:"none",cursor:"pointer",
                background:`linear-gradient(135deg,${G2},${G1})`,color:"#000",
                fontSize:13,fontWeight:"bold",opacity:busy==="jpg"?.6:1,
                display:"flex",alignItems:"center",justifyContent:"center",gap:6}}>
              {busy==="jpg"?"⏳":"⬇️"} JPG
            </button>
            <button onClick={()=>handle("pdf")} disabled={busy==="pdf"}
              style={{padding:"13px 8px",borderRadius:10,border:"none",cursor:"pointer",
                background:"linear-gradient(135deg,#b91c1c,#ef4444)",color:"#fff",
                fontSize:13,fontWeight:"bold",opacity:busy==="pdf"?.6:1,
                display:"flex",alignItems:"center",justifyContent:"center",gap:6}}>
              {busy==="pdf"?"⏳":"📄"} PDF
            </button>
            <button onClick={()=>handle("print")}
              style={{padding:"13px 8px",borderRadius:10,border:"none",cursor:"pointer",
                background:"linear-gradient(135deg,#1e3a5f,#2563eb)",color:"#fff",
                fontSize:13,fontWeight:"bold",
                display:"flex",alignItems:"center",justifyContent:"center",gap:6}}>
              🖨️ Print
            </button>
            <button onClick={()=>handle("share")}
              style={{padding:"13px 8px",borderRadius:10,border:"2px solid #e8d5a0",cursor:"pointer",
                background:copied?"#f0fdf4":"#fff",color:copied?"#16a34a":"#5a2d00",
                fontSize:13,fontWeight:"bold",transition:"all .2s",
                display:"flex",alignItems:"center",justifyContent:"center",gap:6}}>
              {copied?"✅ Copied":"📤 Share"}
            </button>
          </div>
        </>)}

        <div style={{textAlign:"center",marginTop:20,fontSize:10,color:"#c4a862"}}>
          New Krishna Sweets • +91 978 968 3468
        </div>
        <PoweredBy light={true}/>
      </div>
      <style>{`@media print{#cp-btns{display:none!important}body{background:#fff!important}}`}</style>
    </div>
  );
}

